import { ethers } from 'ethers';

// Create a new instance of the Ethers library
const eth = new ethers();

// Set the provider to use for transactions
eth.provider = 'http://localhost:8545';

// Create a new function that will send a transaction to the smart contract
function sendTransaction(params) {
  // Construct the transaction object from the user input parameters
  const txParams = {
    gasPrice: params.gasPrice,
    gasLimit: params.gasLimit,
    nonce: params.nonce,
    value: params.value,
    data: params.data
  };

  // Sign the transaction using the user's private key
  const signedTx = eth.sign(txParams);

  // Send the signed transaction to the network
  const receipt = await eth.sendSignedTransaction(signedTx);

  return receipt;
}

// Export the function for use in our decentralized application frontend
module.exports = { sendTransaction };